class Solution {
public:
    string largestWord(string word, int numFriends) {
        string res = "";
        for (int i = 1; i < word.length(); i++) {
            string first = word.substr(0, i);
            string second = word.substr(i);
            if (second.length() >= numFriends - 1) {
                if (first > res) {
                    res = first;
                }
            }
        }
        if (res.empty()) {
            res = word.substr(0, 1);
        }
        return res;
    }
};

